class Solution {
    public ListNode removeZeroSumSublists(ListNode head) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        ListNode cur = dummy;
        Map<Integer, ListNode> map = new HashMap<>();
        while (cur != null) {
            map.put(cur.val, cur);
            cur = cur.next;
        }
        cur = dummy;
        while (cur != null) {
            int sum = 0;
            while (cur != null) {
                sum += cur.val;
                if (sum == 0) {
                    cur = map.get(sum);
                    break;
                }
                cur = cur.next;
            }
            if (cur != null) {
                cur.next = cur.next.next;
            }
            cur = dummy.next;
        }
        return dummy.next;
    }
}
